import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");
        PrintWriter out = response.getWriter();

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = sanitizeUserInput(userInput);

        // Output sanitized user input
        out.println("<p>User Input: " + sanitizedInput + "</p>");
    }

    private String sanitizeUserInput(String userInput) {
        // Perform proper input sanitization here (e.g., using OWASP ESAPI)
        // Replace potentially harmful characters with their HTML entity equivalents

        return org.owasp.encoder.Encode.forHtml(userInput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
